import play.api.mvc._
import scala.io.Source
import java.nio.file.{Paths, Path, Files}
import javax.inject._

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDir = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    val requestedPath = baseDir.resolve(filename).normalize()

    if (!requestedPath.startsWith(baseDir) || !Files.exists(requestedPath) || Files.isDirectory(requestedPath)) {
      NotFound("File not found or access denied.")
    } else {
      val fileContent = Source.fromFile(requestedPath.toFile).getLines().mkString("\n")
      Ok(fileContent).as("text/plain")
    }
  }
}